/* ══════════════ MINI COMPONENTS ══════════════ */
function NeonRing({pct,color,size=56,stroke=4,children}){
  const r=(size-stroke*2)/2,circ=2*Math.PI*r,off=circ-Math.min(pct/100,1)*circ;
  return(
    <div style={{position:"relative",width:size,height:size,flexShrink:0}}>
      <svg width={size} height={size} style={{transform:"rotate(-90deg)",filter:`drop-shadow(0 0 4px ${color}88)`}}>
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={V.border} strokeWidth={stroke}/>
        <circle cx={size/2} cy={size/2} r={r} fill="none" stroke={color} strokeWidth={stroke} strokeDasharray={circ} strokeDashoffset={off} strokeLinecap="round" style={{transition:"stroke-dashoffset .6s ease",animation:`progress-glow 2s ease-in-out infinite`}}/>
      </svg>
      <div style={{position:"absolute",inset:0,display:"flex",alignItems:"center",justifyContent:"center"}}>{children}</div>
    </div>
  );
}

function GlitchCB({checked,onToggle,color}){
  return(
    <div onClick={onToggle} style={{width:24,height:24,borderRadius:4,border:`1px solid ${checked?color+"44":"transparent"}`,background:checked?color+"22":"transparent",display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",transition:"all .15s",flexShrink:0,boxShadow:checked?`0 0 8px ${color}66`:"none"}}>
      {checked&&<span style={{color,fontSize:14,fontWeight:900,filter:`drop-shadow(0 0 4px ${color})`}}>✓</span>}
    </div>
  );
}

function Panel({children,style={},color,nopad,no3d}){
  const c=color||V.border;
  return(
    <div style={{background:"rgba(10,7,25,0.85)",borderRadius:18,padding:nopad?0:"16px 18px",marginBottom:14,border:"none",backdropFilter:"blur(14px)",WebkitBackdropFilter:"blur(14px)",boxShadow:`0 10px 40px rgba(0,0,0,0.75), 0 2px 12px ${c}16`,transition:"transform 0.25s, box-shadow 0.25s",animation:no3d?"none":"card-3d 8s ease-in-out infinite",...style}}
      onMouseEnter={e=>{if(!no3d){e.currentTarget.style.transform="perspective(800px) rotateX(0deg) rotateY(0deg) scale(1.02)";e.currentTarget.style.boxShadow=`0 20px 60px rgba(0,0,0,0.9), 0 4px 20px ${c}44`;e.currentTarget.style.animation="none";}}}
      onMouseLeave={e=>{if(!no3d){e.currentTarget.style.transform="";e.currentTarget.style.boxShadow="";e.currentTarget.style.animation="card-3d 8s ease-in-out infinite";}}}>
      {children}
    </div>
  );
}

function SLabel({children,color,size}){
  return <div style={{fontFamily:"'Bangers',cursive",fontSize:size||13,letterSpacing:3,color:color||V.cyan,marginBottom:8,textTransform:"uppercase",filter:`drop-shadow(0 0 6px ${color||V.cyan}88)`}}>{children}</div>;
}

function ComicBurst({children,color}){
  return(
    <div style={{position:"relative",display:"inline-flex",alignItems:"center",justifyContent:"center",minWidth:44,minHeight:44}}>
      <svg width="44" height="44" style={{position:"absolute",filter:`drop-shadow(0 0 4px ${color||V.yellow})`}}>
        {[0,20,40,60,80,100,120,140,160,180,200,220,240,260,280,300,320,340].map((angle,i)=>{
          const r1=22,r2=17,a1=(angle*Math.PI)/180,a2=((angle+10)*Math.PI)/180;
          const x1=22+r1*Math.cos(a1),y1=22+r1*Math.sin(a1),x2=22+r2*Math.cos(a2),y2=22+r2*Math.sin(a2);
          return <line key={i} x1="22" y1="22" x2={x1} y2={y1} stroke={color||V.yellow} strokeWidth="1.5" opacity="0.8"/>;
        })}
        <circle cx="22" cy="22" r="16" fill={color||V.yellow} opacity="0.15"/>
        <circle cx="22" cy="22" r="16" fill="none" stroke={color||V.yellow} strokeWidth="1.5"/>
      </svg>
      <div style={{position:"relative",zIndex:1,textAlign:"center"}}>{children}</div>
    </div>
  );
}

