              <div style={{background:`${wDay.color}18`,color:wDay.color,borderRadius:6,padding:"5px 10px",fontFamily:"'Bangers',cursive",fontSize:13,letterSpacing:1,border:`1px solid ${wDay.color}33`,flexShrink:0,filter:`drop-shadow(0 0 4px ${wDay.color}44)`}}>{ex.sets}×{ex.reps}</div>
