/* ══════════════ WEIGHT ══════════════ */
function WeightTracker({weights,setWeights}){
  const [input,setInput]=useState(""),[err,setErr]=useState("");
  const log=async()=>{const w=parseFloat(input);if(isNaN(w)||w<40||w>120){setErr("Enter valid weight (40–120 kg)");return;}setErr("");const t=today();const u=[...weights.filter(x=>x.date!==t),{date:t,w}].sort((a,b)=>a.date.localeCompare(b.date));setWeights(u);await save("weights",u);setInput("");};
  const latest=weights.length?weights[weights.length-1].w:START_WEIGHT;
  const pct=Math.min(Math.max(((latest-START_WEIGHT)/(GOAL_WEIGHT-START_WEIGHT))*100,0),100);

  return(
    <div>
      <Panel color={V.red+"44"}>
        <span className="loki-label">⚖️ Log Today's Weight</span>
        <div style={{display:"flex",gap:10}}>
          <input value={input} onChange={e=>setInput(e.target.value)} onKeyDown={e=>e.key==="Enter"&&log()} placeholder="e.g. 61.5" type="number" step="0.1" style={{flex:1,background:V.bgDeep,border:`1px solid ${V.border}`,borderRadius:8,padding:"13px 16px",color:V.white,fontSize:22,fontFamily:"'Bangers',cursive",letterSpacing:2}}/>
          <button onClick={log} style={{background:`linear-gradient(135deg,${V.red},${V.magenta})`,color:V.white,border:"none",borderRadius:8,padding:"13px 20px",fontFamily:"'Bangers',cursive",fontSize:16,letterSpacing:2,cursor:"pointer",boxShadow:`0 0 16px ${V.red}55`}}>LOG</button>
        </div>
        {err&&<div style={{fontFamily:"'Share Tech Mono',monospace",color:V.red,fontSize:10,marginTop:8}}>{err}</div>}
      </Panel>

      <div style={{background:`linear-gradient(135deg,${V.bgDeep},${V.purple}22)`,border:`2px solid ${V.magenta}`,borderRadius:16,padding:"20px",marginBottom:14,boxShadow:`0 0 30px ${V.magenta}22`}}>
        <div style={{display:"flex",justifyContent:"space-around",marginBottom:16}}>
          {[{l:"START",v:"60 kg",c:V.muted},{l:"CURRENT",v:`${latest} kg`,c:V.cyan},{l:"GOAL",v:"70 kg",c:V.yellow}].map(({l,v,c})=>(
            <div key={l} style={{textAlign:"center"}}><div style={{fontFamily:"'Bangers',cursive",fontSize:30,color:c,letterSpacing:1,filter:`drop-shadow(0 0 8px ${c}88)`}}>{v}</div><div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:8,color:V.muted,marginTop:2}}>{l}</div></div>
          ))}
        </div>
        <div style={{background:V.bgDeep,borderRadius:6,height:14,overflow:"hidden",border:"none",position:"relative"}}>
          <div style={{background:`linear-gradient(90deg,${V.magenta},${V.red},${V.cyan})`,width:`${Math.max(pct,2)}%`,height:"100%",boxShadow:`0 0 20px ${V.cyan}`,transition:"width .5s"}}/>
          <div style={{position:"absolute",inset:0,background:"repeating-linear-gradient(90deg,transparent,transparent 20px,rgba(255,255,255,0.04) 20px,rgba(255,255,255,0.04) 21px)"}}/>
        </div>
        <div style={{textAlign:"center",fontFamily:"'Bangers',cursive",fontSize:14,color:pct>=100?V.cyan:V.soft,letterSpacing:2,marginTop:8}}>{pct>=100?"🎯 70KG ACHIEVED! LOKI COMPLETE!":`${pct.toFixed(1)}% · ${(GOAL_WEIGHT-latest).toFixed(1)} KG REMAINING`}</div>
        <div style={{textAlign:"center",fontFamily:"'Share Tech Mono',monospace",fontSize:9,color:V.muted,marginTop:4}}>DAY_{daysSince()} · WEEK_{weekNum()}</div>
      </div>

      {weights.length>=2&&(
        <Panel>
          <SLabel>Weight Chart</SLabel>
          <WtChart weights={weights}/>
        </Panel>
      )}

      <Panel>
        <SLabel>History</SLabel>
        {weights.length===0&&<div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:11,color:V.muted,textAlign:"center",padding:"16px"}}>NO_ENTRIES_YET — LOG_FIRST_WEIGHT</div>}
        {[...weights].reverse().map(w=>{
          const prev=weights[weights.findIndex(x=>x.date===w.date)-1],diff=prev?+(w.w-prev.w).toFixed(1):null;
          return(
            <div key={w.date} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"11px 0",borderBottom:`1px solid ${V.border}`}}>
              <div><div style={{fontFamily:"'Bangers',cursive",fontSize:18,color:V.white,letterSpacing:1}}>{w.w} kg</div><div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:9,color:V.muted,marginTop:1}}>{fmtDate(w.date)}</div></div>
              <div style={{display:"flex",alignItems:"center",gap:10}}>
                {diff!==null&&<span style={{fontFamily:"'Bangers',cursive",fontSize:16,letterSpacing:1,color:diff>0?V.cyan:diff<0?"#4ADE80":V.muted,filter:`drop-shadow(0 0 4px ${diff>0?V.cyan:"#4ADE80"}88)`}}>{diff>0?"+":""}{diff} kg</span>}
                <button onClick={async()=>{const u=weights.filter(x=>x.date!==w.date);setWeights(u);await save("weights",u);}} style={{background:V.panelAlt,border:`1px solid ${V.border}`,color:V.muted,borderRadius:6,padding:"4px 10px",cursor:"pointer",fontFamily:"'Share Tech Mono',monospace",fontSize:11}}>×</button>
              </div>
            </div>
          );
        })}
      </Panel>
    </div>
  );
}
function WtChart({weights}){
  const data=weights.slice(-30);if(data.length<2)return null;
  const vals=data.map(w=>w.w),minV=Math.min(...vals)-0.5,maxV=Math.max(Math.max(...vals)+0.5,70.5),H=90,W=300;
  const goalY=H-((70-minV)/(maxV-minV))*H;
  const pts=data.map((w,i)=>`${(i/(data.length-1))*W},${H-((w.w-minV)/(maxV-minV))*H}`).join(" ");
  const area=`M0,${H} `+data.map((w,i)=>`L${(i/(data.length-1))*W},${H-((w.w-minV)/(maxV-minV))*H}`).join(" ")+` L${W},${H} Z`;
  return(<svg viewBox={`-20 0 ${W+40} ${H+24}`} style={{width:"100%"}}><defs><linearGradient id="wg" x1="0" x2="0" y1="0" y2="1"><stop offset="0%" stopColor={V.cyan} stopOpacity="0.3"/><stop offset="100%" stopColor={V.cyan} stopOpacity="0"/></linearGradient></defs><line x1={0} y1={goalY} x2={W} y2={goalY} stroke={V.yellow} strokeWidth="1.5" strokeDasharray="5,4" opacity="0.7"/><text x={W+4} y={goalY+4} fontSize="9" fill={V.yellow} fontFamily="'Share Tech Mono',monospace">70kg</text><path d={area} fill="url(#wg)"/><polyline points={pts} fill="none" stroke={V.cyan} strokeWidth="2.5" strokeLinejoin="round" style={{filter:`drop-shadow(0 0 4px ${V.cyan})`}}/>{data.map((w,i)=>{const x=(i/(data.length-1))*W,y=H-((w.w-minV)/(maxV-minV))*H;return<circle key={i} cx={x} cy={y} r={i===data.length-1?5:3} fill={V.cyan} stroke={V.bgDeep} strokeWidth="1.5"/>;})} {data.map((w,i)=>{if(i===0||i===data.length-1||i===Math.floor(data.length/2))return<text key={i} x={(i/(data.length-1))*W} y={H+16} textAnchor="middle" fontSize="8" fill={V.muted} fontFamily="'Share Tech Mono',monospace">{fmtDate(w.date)}</text>;return null;})}</svg>);
}

/* ══════════════ TIPS ══════════════ */
function TipsTab({mealChecked,workoutChecked,weights}){
  const [sec,setSec]=useState("lean");
  const days=Array.from({length:14},(_,i)=>{const d=new Date();d.setDate(d.getDate()-13+i);return d.toISOString().slice(0,10);});
  const stats=days.map(date=>{const mc=mealChecked[date]||{},wc=workoutChecked[date]||{};const mc5=MEALS_DATA.filter(m=>m.items.every(i=>mc[i.id])).length;const ex=WORKOUT_DAYS.flatMap(d=>d.exercises||[]).filter(e=>wc[e.id]).length;return{date,mc5,ex,score:Math.round((mc5/5)*50+(Math.min(ex,6)/6)*50)};});
  const avg=Math.round(stats.reduce((s,x)=>s+x.score,0)/stats.length);
  const latest=weights.length?weights[weights.length-1].w:START_WEIGHT;
  const S=[{id:"lean",icon:"💎",title:"PURE MUSCLE",color:V.red},{id:"jaw",icon:"🗿",title:"JAWLINE",color:V.magenta},{id:"prog",icon:"📈",title:"PROGRESS",color:V.cyan},{id:"road",icon:"🗺️",title:"ROADMAP",color:V.yellow}];

  return(
    <div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:14}}>
        {S.map(s=>(<div key={s.id} onClick={()=>setSec(s.id)} style={{background:sec===s.id?`${s.color}18`:V.panel,borderRadius:12,padding:"13px 16px",border:`${sec===s.id?"2px":"1px"} solid ${sec===s.id?s.color:V.border}`,cursor:"pointer",display:"flex",alignItems:"center",gap:10,transition:"all .2s",boxShadow:sec===s.id?`0 0 16px ${s.color}33`:"none"}}>
          <span style={{fontSize:22}}>{s.icon}</span>
          <span style={{fontFamily:"'Bangers',cursive",color:sec===s.id?s.color:V.soft,fontSize:14,letterSpacing:2}}>{s.title}</span>
        </div>))}
      </div>

      {sec==="lean"&&(
        <div>
          {/* Miles Morales themed — crimson + web texture */}
          <div style={{background:`linear-gradient(135deg,${V.red}18,${V.bgDeep})`,border:`1px solid ${V.red}55`,borderRadius:16,padding:"16px",marginBottom:12,position:"relative",overflow:"hidden"}}>
            <div style={{position:"absolute",right:-10,bottom:-20,fontSize:80,opacity:0.04,lineHeight:1,pointerEvents:"none",userSelect:"none",transform:"rotate(15deg)"}}>🕷️</div>
            <SLabel color={V.red}>LEAN BULK — PURE MUSCLE</SLabel>
            <div style={{fontFamily:"'Rajdhani',sans-serif",fontSize:13,color:V.soft,lineHeight:1.8,fontWeight:600}}>At 60kg / 5'7" your fat is naturally low. Surplus is only <span style={{color:V.red,fontWeight:800}}>+500 cal</span> — builds muscle WITHOUT visible fat. Dirty bulk = fat face. This plan keeps you lean.</div>
          </div>
          <Panel>
            <SLabel color="#4ADE80">✅ Rules for Pure Muscle</SLabel>
            {[["Small surplus (+500 cal)","~0.5–0.8 kg/month. Almost 100% muscle. Not dirty bulk."],["160g protein daily","More protein = more muscle per calorie."],["Only 1.5 tbsp oil/day","Minimum fat. Oil only for cooking."],["Low sodium","High salt = water retention = puffy face."],["No junk, no sugar","1 samosa = 300 empty cal, zero protein."],["20 min walk on rest days","Burns 150 cal, keeps you from getting soft."]].map(([t,d])=>(<div key={t} style={{marginBottom:10,paddingBottom:10,borderBottom:`1px solid ${V.border}`}}><div style={{fontFamily:"'Rajdhani',sans-serif",fontSize:13,color:V.white,fontWeight:700,marginBottom:2}}>▸ {t}</div><div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:9,color:V.muted,lineHeight:1.6}}>{d}</div></div>))}
          </Panel>
        </div>
      )}

      {sec==="jaw"&&(
        <div>
          {/* Gwen Stacy themed — cyan + pink gradient */}
          <div style={{background:`linear-gradient(135deg,${V.cyan}12,${V.magenta}12)`,border:`1px solid ${V.magenta}55`,borderRadius:16,padding:"16px",marginBottom:12}}>
            <SLabel color={V.magenta}>🗿 JAWLINE GUIDE</SLabel>
            <div style={{fontFamily:"'Rajdhani',sans-serif",fontSize:13,color:V.soft,lineHeight:1.8,fontWeight:600}}>Face fat = body fat %. Lean bulk keeps fat low = face sharpens. These habits speed it up massively.</div>
          </div>
          {[
            {title:"🧂 LOW SALT",color:V.cyan,tips:[["Cut salt by 50%","High sodium = face puffs up. Minimum salt."],["No pickles/packets","Hidden sodium = puffy face 24 hrs."],["Lemon juice instead","Adds flavour, zero sodium."]]},
            {title:"💧 HYDRATION",color:V.cyan,tips:[["3.75L water daily","More water = LESS retention = thinner face."],["No sugary drinks","Causes facial bloating within hours."],["Green tea (no sugar)","Reduces puffiness."]]},
            {title:"🏋️ JAW EXERCISES",color:V.magenta,tips:[["Mewing","Tongue flat on roof of mouth ALWAYS. Reshapes jawline over months."],["Chew hard food daily","Raw carrots, cucumber. Works masseter muscles."],["Jaw clench 3×20","Gently clench 1 sec, release."],["Chin tucks 3×15","Pull chin back, hold 5 sec."]]},
            {title:"😴 SLEEP",color:V.purple,tips:[["Sleep on your back","Side sleeping = facial puffiness."],["8 hrs minimum","Cortisol = face water retention."],["Zero alcohol","Biggest jawline killer."]]},
          ].map(s=>(<Panel key={s.title} color={s.color+"33"}><SLabel color={s.color} size={12}>{s.title}</SLabel>{s.tips.map(([t,d])=>(<div key={t} style={{marginBottom:8,paddingBottom:8,borderBottom:`1px solid ${V.border}`}}><div style={{fontFamily:"'Rajdhani',sans-serif",fontSize:13,color:V.white,fontWeight:700,marginBottom:2}}>{t}</div><div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:9,color:V.muted,lineHeight:1.6}}>{d}</div></div>))}</Panel>))}
        </div>
      )}

      {sec==="prog"&&(
        <div>
          <div style={{background:`linear-gradient(135deg,${V.bgDeep},${V.cyan}18)`,border:`2px solid ${V.cyan}`,borderRadius:16,padding:"20px",marginBottom:14,textAlign:"center",boxShadow:`0 0 30px ${V.cyan}22`,position:"relative",overflow:"hidden"}}>
            <img src={IMG_MILES_FACE} alt="" style={{position:"absolute",right:10,bottom:-10,height:120,objectFit:"contain",objectPosition:"top",opacity:0.2,pointerEvents:"none",animation:"float2 6s ease-in-out infinite",filter:"drop-shadow(0 0 12px #00FFFF88)"}}/>
            <div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:8,color:V.muted,letterSpacing:2,marginBottom:6}}>14-DAY_CONSISTENCY_SCORE</div>
            <div style={{fontFamily:"'Bangers',cursive",fontSize:66,color:avg>=70?V.cyan:avg>=40?V.yellow:V.red,letterSpacing:3,lineHeight:1,filter:`drop-shadow(0 0 20px ${avg>=70?V.cyan:avg>=40?V.yellow:V.red}88)`}}>{avg}<span style={{fontSize:26}}>/100</span></div>
            <div style={{fontFamily:"'Rajdhani',sans-serif",fontSize:13,color:V.soft,fontWeight:700,marginTop:6}}>{avg>=80?"🔥 ELITE! LOKI UNSTOPPABLE!":avg>=60?"💪 GOOD — STAY CONSISTENT":avg>=40?"⚠️ INCONSISTENT — FIX IT":"❌ NEEDS SERIOUS WORK"}</div>
          </div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:14}}>
            {[{l:"MEAL DAYS",v:`${stats.filter(s=>s.mc5>=3).length}/14`,c:V.red},{l:"GYM DAYS",v:`${stats.filter(s=>s.ex>0).length}/14`,c:V.magenta},{l:"GAINED",v:`+${(latest-START_WEIGHT).toFixed(1)}kg`,c:V.cyan}].map(({l,v,c})=>(<div key={l} style={{background:V.panel,borderRadius:12,padding:"14px 8px",border:"none",textAlign:"center"}}><div style={{fontFamily:"'Bangers',cursive",fontSize:22,color:c,filter:`drop-shadow(0 0 8px ${c}88)`}}>{v}</div><div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:8,color:V.muted,marginTop:3}}>{l}</div></div>))}
          </div>
          <Panel>
            <SLabel>14-Day Heatmap</SLabel>
            <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
              {stats.map(s=>{const col=s.score>=80?V.cyan:s.score>=50?V.red:s.score>=20?V.purple:V.border;return(
                <div key={s.date} style={{flex:"1 1 calc(14% - 5px)",minWidth:32}}>
                  <div style={{height:32,borderRadius:6,background:`${col}22`,border:"none",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Bangers',cursive",fontSize:11,color:col,boxShadow:s.score>0?`0 0 6px ${col}44`:"none"}}>{s.score||""}</div>
                  <div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:7,color:V.muted,textAlign:"center",marginTop:3}}>{fmtDate(s.date).split(" ")[0]}</div>
                </div>
              );})}
            </div>
          </Panel>
        </div>
      )}

      {sec==="road"&&(
        <Panel>
          <SLabel color={V.yellow}>5-MONTH ROADMAP · 60→70 KG</SLabel>
          {[{m:"Month 1",g:"+1.5–2 kg",to:"~62 kg",n:"Muscle memory fires 🔥"},{m:"Month 2",g:"+1.5–2 kg",to:"~64 kg",n:"Rapid rebuild"},{m:"Month 3",g:"+1.5–2 kg",to:"~66 kg",n:"Real hypertrophy"},{m:"Month 4",g:"+1–1.5 kg",to:"~67.5 kg",n:"Grind phase"},{m:"Month 5",g:"+1–1.5 kg",to:"~69 kg",n:"Final push 💪"}].map((r,i)=>{
            const reached=latest>=(60+i*2),c=reached?V.cyan:V.muted;
            return(<div key={r.m} style={{display:"flex",gap:12,alignItems:"center",marginBottom:10,padding:"11px 14px",background:reached?`${V.cyan}08`:V.panelAlt,borderRadius:10,border:"none"}}>
              <div style={{width:10,height:10,borderRadius:"50%",background:reached?V.cyan:V.border,flexShrink:0,boxShadow:reached?`0 0 8px ${V.cyan}`:"none"}}/>
              <div style={{flex:1}}><span style={{fontFamily:"'Rajdhani',sans-serif",fontSize:14,color:c,fontWeight:800}}>{r.m}</span><span style={{fontFamily:"'Share Tech Mono',monospace",fontSize:9,color:V.muted,marginLeft:8}}>{r.n}</span></div>
              <div style={{textAlign:"right"}}><div style={{fontFamily:"'Bangers',cursive",fontSize:14,color:c,letterSpacing:1}}>{r.g}</div><div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:8,color:V.muted}}>{r.to}</div></div>
            </div>);
          })}
        </Panel>
      )}
    </div>
  );
}

/* ══════════════ APP ROOT ══════════════ */
export default function App(){
  const [tab,setTab]=useState("home");
  const [mealChecked,setMealChecked]=useState({});
  const [workoutChecked,setWorkoutChecked]=useState({});
  const [waterChecked,setWaterChecked]=useState({});
  const [weights,setWeights]=useState([]);
  const [workoutDay,setWorkoutDay]=useState(0);
  const [loading,setLoading]=useState(true);

  useEffect(()=>{(async()=>{
    const t=today();
    const mc={};const md=await load(`meals:${t}`);if(md)mc[t]=md;
    for(let i=1;i<=30;i++){const d=new Date();d.setDate(d.getDate()-i);const dk=d.toISOString().slice(0,10);const v=await load(`meals:${dk}`);if(v)mc[dk]=v;}
    setMealChecked(mc);
    const wc={};const wd=await load(`workout:${t}`);if(wd)wc[t]=wd;setWorkoutChecked(wc);
    const wday=await load("workoutDay");if(wday!==null)setWorkoutDay(wday);
    const wts=await load("weights");if(wts)setWeights(wts);
    const watr={};const watd=await load(`water:${t}`);if(watd)watr[t]=watd;setWaterChecked(watr);
    setLoading(false);
  })();},[]);

  const TABS=[{id:"home",icon:"🕷️",label:"HOME"},{id:"meals",icon:"🍽️",label:"MEALS"},{id:"grocery",icon:"🛒",label:"SHOP"},{id:"workout",icon:"💪",label:"GYM"},{id:"water",icon:"💧",label:"WATER"},{id:"weight",icon:"⚖️",label:"WEIGHT"},{id:"tips",icon:"💎",label:"TIPS"}];
  const ACCENT={home:V.red,meals:V.magenta,grocery:"#4ADE80",workout:V.red,water:V.cyan,weight:V.yellow,tips:V.magenta};
  const LABELS={home:"DASHBOARD",meals:"MEAL_TRACKER",grocery:"GROCERY_LIST",workout:"GYM_TRACKER",water:"WATER_SYSTEM",weight:"WEIGHT_LOG",tips:"TIPS_&_PROGRESS"};

  /* 3D Web canvas effect — must be before any conditional return */
  useEffect(()=>{
    if(loading) return;
    const canvas=document.getElementById("loki-web-canvas");
    if(!canvas)return;
    canvas.width=window.innerWidth; canvas.height=window.innerHeight;
    const ctx=canvas.getContext("2d");
    const cx=canvas.width/2, cy=canvas.height/2;
    const maxR=Math.max(canvas.width,canvas.height)*0.75;
    const spokes=16, rings=10; let frame=0, raf;
    const draw=()=>{
      ctx.clearRect(0,0,canvas.width,canvas.height);
      ctx.save(); ctx.translate(cx,cy); ctx.rotate(frame*0.0005);
      const pulse=1+Math.sin(frame*0.012)*0.055;
      for(let i=0;i<spokes;i++){
        const a=(i/spokes)*Math.PI*2;
        const g=ctx.createLinearGradient(0,0,Math.cos(a)*maxR*pulse,Math.sin(a)*maxR*pulse);
        g.addColorStop(0,"rgba(238,33,86,0.9)"); g.addColorStop(0.45,"rgba(120,0,220,0.4)"); g.addColorStop(1,"rgba(0,255,255,0.1)");
        ctx.beginPath(); ctx.moveTo(0,0); ctx.lineTo(Math.cos(a)*maxR*pulse,Math.sin(a)*maxR*pulse);
        ctx.strokeStyle=g; ctx.lineWidth=1.4; ctx.stroke();
      }
      for(let r=1;r<=rings;r++){
        const rad=(r/rings)*maxR*pulse;
        ctx.beginPath();
        for(let i=0;i<=spokes;i++){
          const a=(i/spokes)*Math.PI*2;
          const wob=1+Math.sin(frame*0.015+r*0.9+i*0.5)*0.035;
          const x=Math.cos(a)*rad*wob, y=Math.sin(a)*rad*wob;
          i===0?ctx.moveTo(x,y):ctx.lineTo(x,y);
        }
        ctx.closePath();
        const alpha=0.08+(r/rings)*0.22;
        ctx.strokeStyle=`hsla(${260+r*12},85%,70%,${alpha*1.8})`; ctx.lineWidth=r<=2?0.8:1.2; ctx.stroke();
      }
      const g2=ctx.createRadialGradient(0,0,0,0,0,80);
      g2.addColorStop(0,"rgba(238,33,86,0.85)"); g2.addColorStop(1,"rgba(238,33,86,0)");
      ctx.beginPath(); ctx.arc(0,0,80,0,Math.PI*2); ctx.fillStyle=g2; ctx.fill();
      ctx.restore(); frame++; raf=requestAnimationFrame(draw);
    };
    draw();
    return()=>cancelAnimationFrame(raf);
  },[loading]);

  if(loading)return(
    <div style={{minHeight:"100vh",background:V.bg,display:"flex",alignItems:"center",justifyContent:"center",flexDirection:"column",gap:20,position:"relative",overflow:"hidden"}}>
      <style>{GLOBAL_CSS+`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
      <div className="hex-bg"/>
      <div className="light-leak-left"/><div className="light-leak-right"/>
      <img src={IMG_MILES_ACTION} alt="" style={{height:240,objectFit:"contain",animation:"float2 4s ease-in-out infinite, hero-enter 0.8s ease-out",filter:`drop-shadow(0 0 30px ${V.red}88) drop-shadow(0 0 60px ${V.red}44)`}}/>
      <div className="glitch-text" style={{fontFamily:"'Bangers',cursive",fontSize:36,color:V.white,letterSpacing:6,marginTop:-20}}>LOKI WORKOUT</div>
      <div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:10,color:V.muted,letterSpacing:3}}>INITIALIZING...</div>
      <div style={{width:44,height:44,border:`2px solid ${V.border}`,borderTop:`2px solid ${V.red}`,borderRadius:"50%",animation:"spin 0.7s linear infinite",boxShadow:`0 0 20px ${V.red}66`}}/>
    </div>
  );

  const accent=ACCENT[tab];

  return(
    <div style={{minHeight:"100vh",background:V.bg,fontFamily:"'Rajdhani',sans-serif",paddingBottom:76,position:"relative"}}>
      <style>{GLOBAL_CSS}</style>
      {/* 3D Animated Spider-Web Background */}
      <canvas id="loki-web-canvas" style={{position:"fixed",inset:0,zIndex:0,pointerEvents:"none",opacity:0.65,width:"100%",height:"100%"}}/>
      <div className="hex-bg"/>
      
      <div className="light-leak-left"/><div className="light-leak-right"/>

      {/* HEADER */}
      <div style={{background:`linear-gradient(180deg,${V.bgDeep}f0,${V.bgDeep}cc)`,padding:"12px 18px",borderBottom:"none",position:"sticky",top:0,zIndex:50,backdropFilter:"blur(20px)",boxShadow:`0 4px 30px rgba(0,0,0,0.6)`,position:"sticky"}}>
        <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}>
          <div style={{display:"flex",alignItems:"center",gap:10}}>
            <div style={{width:40,height:40,borderRadius:10,overflow:"hidden",border:`2px solid ${V.red}88`,boxShadow:`0 0 16px ${V.red}66`,flexShrink:0}}>
              <img src={IMG_MILES_FACE} alt="Miles" style={{width:"100%",height:"100%",objectFit:"cover",objectPosition:"top center",transform:"scale(1.3) translateY(5px)"}}/>
            </div>
            <div>
              <div style={{fontFamily:"'Bangers',cursive",fontSize:20,color:V.white,letterSpacing:4,lineHeight:1}} className="glitch-text">LOKI WORKOUT</div>
              <div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:8,color:V.muted,letterSpacing:2}}>{LABELS[tab]}</div>
            </div>
          </div>
          <div style={{textAlign:"right"}}>
            <div style={{fontFamily:"'Share Tech Mono',monospace",fontSize:9,color:V.muted}}>{new Date().toLocaleDateString("en-IN",{weekday:"short",day:"numeric",month:"short"}).toUpperCase()}</div>
            <div style={{fontFamily:"'Bangers',cursive",fontSize:12,color:accent,letterSpacing:2,filter:`drop-shadow(0 0 6px ${accent}88)`}}>WK{weekNum()} · DAY{daysSince()}</div>
          </div>
        </div>
      </div>

      <div style={{maxWidth:520,margin:"0 auto",padding:"14px 14px 0",position:"relative",zIndex:5}}>
        {tab==="home"    &&<Dashboard mealChecked={mealChecked} workoutChecked={workoutChecked} weights={weights} workoutDay={workoutDay} waterChecked={waterChecked} setTab={setTab}/>}
        {tab==="meals"   &&<MealTracker mealChecked={mealChecked} setMealChecked={setMealChecked}/>}
        {tab==="grocery" &&<GroceryTab/>}
        {tab==="workout" &&<WorkoutTracker workoutChecked={workoutChecked} setWorkoutChecked={setWorkoutChecked} workoutDay={workoutDay} setWorkoutDay={setWorkoutDay}/>}
        {tab==="water"   &&<WaterTab waterChecked={waterChecked} setWaterChecked={setWaterChecked}/>}
        {tab==="weight"  &&<WeightTracker weights={weights} setWeights={setWeights}/>}
        {tab==="tips"    &&<TipsTab mealChecked={mealChecked} workoutChecked={workoutChecked} weights={weights}/>}
      </div>

      {/* BOTTOM NAV */}
      <div style={{position:"fixed",bottom:0,left:0,right:0,background:`${V.bgDeep}f5`,borderTop:"none",display:"flex",padding:"5px 0 10px",zIndex:100,backdropFilter:"blur(20px)",boxShadow:"0 -4px 30px rgba(0,0,0,0.7)"}}>
        {TABS.map(t=>{
          const active=tab===t.id,col=ACCENT[t.id];
          return(
            <button key={t.id} onClick={()=>setTab(t.id)} style={{flex:1,background:"transparent",border:"none",cursor:"pointer",padding:"4px 2px",display:"flex",flexDirection:"column",alignItems:"center",gap:3}}>
              <div style={{width:30,height:30,borderRadius:8,background:active?`${col}22`:"transparent",border:"none",display:"flex",alignItems:"center",justifyContent:"center",fontSize:15,transition:"all .2s",boxShadow:active?`0 0 12px ${col}66`:"none"}}>{t.icon}</div>
              <span style={{fontFamily:"'Bangers',cursive",fontSize:7,color:active?col:V.muted,letterSpacing:1,filter:active?`drop-shadow(0 0 4px ${col}88)`:"none"}}>{t.label}</span>
            </button>
          );
        })}
      </div>
    </div>
  );
}
